+        let original = "fn main() {}\n";
+        fs::write(&file_path, original).unwrap();
+
+        let change = TestCodeChange::for_file(&file_path).unwrap();
+
+        // Apply
+        change.apply().unwrap();
+        assert!(
+            fs::read_to_string(&file_path)
