+
+        // Apply again
+        change.apply().unwrap();
+        assert!(
+            fs::read_to_string(&file_path)
+                .unwrap()
+                .contains(&change.change_id)
+        );
+
+        info!("TEST PASS: test_apply_revert_apply");
+    }
